solution: ```class Solution {
public:
    bool canVisitAllRooms(vector<vector<int>>& rooms) {
        int n = rooms.size();
        vector<bool> visited(n, false);
        queue<int> q;
        q.push(0);
        visited[0] = true;
        int count = 1;
        while (!q.empty()) {
            int room = q.front(); q.pop();
            for (int key : rooms[room]) {
                if (!visited[key]) {
                    visited[key] = true;
                    q.push(key);
                    ++count;
                }
            }
        }
        return count == n;
    }
};
```
efficiency: HIGH
time complexity: O(N + K) where N is the number of rooms and K is the total number of keys
space complexity: O(N)
energy implications: LOW
explanation: Breadth-first search from room 0 collects all reachable rooms; if the count equals N, every room was unlocked.

